def get_musician_info(name):
    musicians_db = {
        "Caughey Roberts": {
            "birth_year": 1912,
            "death_year": 1990,
            "instruments": ["alto saxophone", "baritone saxophone", "clarinet"]
        }
    }
    return musicians_db.get(name, {})

# Example usage:
print(get_musician_info("Caughey Roberts"))

